import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"77. Secure Employment","description":"","frontmatter":{"title":"77. Secure Employment","eba":"Health Allied & Managers Admin 2021-2025","topics":["employment","staffing"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/classification-staffing/77-secure-employment.md","filePath":"ebas/has-managers-admin/common-terms/classification-staffing/77-secure-employment.md"}'),r={name:"ebas/has-managers-admin/common-terms/classification-staffing/77-secure-employment.md"};function i(s,e,l,m,c,p){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_77-secure-employment" tabindex="-1">77. Secure Employment <a class="header-anchor" href="#_77-secure-employment" aria-label="Permalink to &quot;77. Secure Employment&quot;">​</a></h1><p><strong>77.1</strong> The parties are committed to preferencing secure employment and reducing labour hire within the Victorian Public Health Sector.</p><p><strong>77.2</strong> Vacancies</p><p><strong>(a)</strong> Where available hours of no greater than sixteen (16) hours a week arise within a department through the vacating of all or part of an existing position, the Employer may, as an alternative to advertising at 77.2(b) to 77.2(d),invite expressions of interest from part-time or casual Employees within the department. Where the process set out at sub-clause 77.2(a) is not utilised, the responsible manager will initiate action to advertise the vacant position or available hours, internally at first instance and then externally if necessary, immediately after receiving notice of resignation</p><p><strong>(b)</strong> Where a vacancy arises within a department, the responsible manager will initiate action to advertise the vacant position or available hours, internally at first instance and then externally if necessary, immediately after receiving notice of resignation.</p><p><strong>(c)</strong> Where it is impracticable to seek internal applicants at first instance due to staff shortages in the classification in which the vacancy arises, the Employer may advertise for internal/external applicants concurrently.</p><p><strong>(d)</strong> The Employer will advertise all vacancies that arise where the vacancy relates to a position that, but for the vacancy occurring would have been ongoing, as soon as practicable (ordinarily within 8 working days).</p><p><strong>77.3</strong> Unplanned Absences</p><p><strong>(a)</strong> The Employer agrees to replace staff on planned or unplanned absences, where workload cannot be deferred, rearranged or reallocated without generating an unreasonable workload.</p><p><strong>(b)</strong> Where additional shifts are required to replace-planned or unplanned absences, prior to engaging agency staff, the Employer will give preference to:</p><p><strong>(i)</strong> existing part-time Employees who would not attract Overtime by performing the additional shift;</p><p><strong>(ii)</strong> casual Employees who would not attract Overtime by performing the additional shift;</p><p><strong>(iii)</strong> part time Employees or full-time Employees who would attract Overtime by performing the additional shift (subject to <a href="/eba/ebas/has-managers-admin/common-terms/classification-staffing/78-workload-management.html">Clause 78.2</a> – Work-related Fatigue and <a href="/eba/ebas/has-managers-admin/common-terms/hours-of-work/52-reasonable-additional-hours.html">Clause 52</a> – Reasonable Additional Hours)</p><p><strong>(iv)</strong> casual Employees who would attract Overtime by performing the additional shift (subject to <a href="/eba/ebas/has-managers-admin/common-terms/classification-staffing/78-workload-management.html">Clause 78.2</a> – Work-related Fatigue and <a href="/eba/ebas/has-managers-admin/common-terms/hours-of-work/52-reasonable-additional-hours.html">Clause 52</a> – Reasonable Additional Hours)</p><p><strong>77.4</strong> Promotion of Full-Time employment</p><p><strong>(a)</strong> Within 3 months of the commencement date of this Agreement, Employers will write to all Employees who are contracted to work a minimum of 37 hours per week, or 74 hours per fortnight, to offer a conversion to Full-Time employment in accordance with subclause 20 (Full-time Employment).</p><p><strong>(b)</strong> Where an Employee declines the offer to convert to Full-Time employment under subclause 77.4(a), that response will be provided to the Employer in writing.</p><p><strong>(c)</strong> Where a conversion to Full-Time employment occurs, the Employer will provided the Employee with a Letter of Appointment setting out the revised employment arrangement.</p><p><strong>(d)</strong> Nothing within this clause 77.4 will prevent an Employee from making a request to convert to Full-Time employment after the commencement date of this Agreement. These requests will be dealt with in accordance with <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/22-part-time-review-of-hours.html">Clause 22</a> (Part-Time Review of Hours).</p>',19)])])}const g=t(r,[["render",i]]);export{d as __pageData,g as default};
